export const EMAIL_BODY_CSS = `
@font-face {
  font-family: 'Google Sans Flex';
  font-style: normal;
  font-weight: 400;
  font-display: swap;
  src: url('data:font/woff2;base64,') format('woff2');
}

@font-face {
  font-family: 'Google Sans Flex';
  font-style: normal;
  font-weight: 500;
  font-display: swap;
  src: url('data:font/woff2;base64,') format('woff2');
}

@font-face {
  font-family: 'Google Sans Flex';
  font-style: normal;
  font-weight: 600;
  font-display: swap;
  src: url('data:font/woff2;base64,') format('woff2');
}

@font-face {
  font-family: 'Google Sans Flex';
  font-style: normal;
  font-weight: 700;
  font-display: swap;
  src: url('data:font/woff2;base64,') format('woff2');
}

html {
  height: auto !important;
  min-height: 0 !important;
  background-color: transparent;
  color-scheme: light;
}

body {
  height: auto !important;
  min-height: 0 !important;
  margin: 0;
  padding: 0;
  background-color: transparent;
  font-family: 'Google Sans Flex', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
  font-size: 14px;
  line-height: 1.6;
  word-wrap: break-word;
  overflow-wrap: break-word;
  overflow-x: hidden;
  overflow-y: hidden;
}


.aster_quote,
.gmail_quote,
.protonmail_quote,
.yahoo_quoted,
.moz-cite-prefix {
  display: none;
}

.blocked-image {
  display: inline-block;
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 12px;
  background-color: #f3f4f6;
  color: #9ca3af;
  border: 1px dashed #e5e7eb;
}

.blocked-remote-image {
  display: inline-block;
  min-width: 60px;
  min-height: 20px;
  padding: 8px;
  border-radius: 4px;
  background-color: #f3f4f6;
  border: 1px dashed #e5e7eb;
  cursor: pointer;
}

.remote-content-banner {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  margin-bottom: 12px;
  border-radius: 8px;
  font-size: 13px;
  background-color: #f3f4f6;
  border: 1px solid #e5e7eb;
  color: #374151;
}

.remote-content-banner button {
  margin-left: auto;
  padding: 4px 12px;
  border-radius: 6px;
  font-size: 12px;
  font-weight: 500;
  background-color: #3b82f6;
  color: white;
  border: none;
  cursor: pointer;
  transition: opacity 0.15s;
}

.remote-content-banner button:hover {
  opacity: 0.9;
}

details.aster-forwarded-collapse {
  margin-top: 12px;
  border-top: 1px solid #e5e7eb;
  padding-top: 4px;
}

details.aster-forwarded-collapse > summary {
  cursor: pointer;
  color: #6b7280;
  font-size: 13px;
  font-family: 'Google Sans Flex', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  padding: 6px 0;
  user-select: none;
  outline: none;
  list-style: none;
}

details.aster-forwarded-collapse > summary::-webkit-details-marker {
  display: none;
}

details.aster-forwarded-collapse > summary::before {
  content: '\\25B6';
  display: inline-block;
  font-size: 8px;
  margin-right: 6px;
  margin-inline-end: 6px;
  transition: transform 0.15s ease;
}

details[open].aster-forwarded-collapse > summary::before {
  transform: rotate(90deg);
}

details.aster-forwarded-collapse > .aster-forwarded-content {
  padding-top: 8px;
}

.aster-quoted-wrapper {
  margin-top: 8px;
}

.aster-quote-toggle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  height: 16px;
  padding: 0 4px;
  border-radius: 3px;
  border: 1px solid rgba(128, 128, 128, 0.25);
  background: rgba(128, 128, 128, 0.08);
  color: rgba(100, 100, 100, 0.7);
  cursor: pointer;
  font-size: 8px;
  letter-spacing: 1.5px;
  line-height: 1;
  vertical-align: middle;
  user-select: none;
}

.aster-quote-toggle:hover {
  background: rgba(128, 128, 128, 0.2);
  border-color: rgba(128, 128, 128, 0.45);
}

.aster-quote-toggle.aster-quote-expanded {
  background: rgba(128, 128, 128, 0.2);
  border-color: rgba(128, 128, 128, 0.45);
}

.aster-quoted-content {
  margin-top: 8px;
  color: #5f6368;
  font-size: 14px;
  line-height: 20px;
}

.aster-quoted-content .aster_quote,
.aster-quoted-content .gmail_quote,
.aster-quoted-content .protonmail_quote,
.aster-quoted-content .yahoo_quoted,
.aster-quoted-content .moz-cite-prefix,
.aster-forwarded-content .aster_quote,
.aster-forwarded-content .gmail_quote,
.aster-forwarded-content .protonmail_quote {
  display: block;
  margin: 0;
  padding: 0;
}

.aster-quoted-content .aster_quote_attr,
.aster-quoted-content .gmail_attr {
  color: #5f6368;
  font-size: 12px;
  margin-bottom: 4px;
}

.aster-quoted-content blockquote {
  margin: 0 0 0 0;
  padding: 0 0 0 12px;
  border-left: 2px solid #dadce0;
  color: #5f6368;
}

.aster-quoted-content blockquote blockquote {
  border-left-color: #c4c7cc;
}

img {
  max-width: 100%;
  height: auto;
}

@media print {
  body {
    overflow: visible !important;
  }

  details.aster-forwarded-collapse > .aster-forwarded-content {
    display: block !important;
  }

  .aster-quoted-content {
    display: block !important;
  }
}
`;

